<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Hostel'; if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); executeSql('INSERT INTO hostel_rooms(room_no,capacity,occupied,hostel_fee) VALUES (?,?,?,?)',[post('room_no'),(int)post('capacity','1'),(int)post('occupied','0'),(float)post('hostel_fee','0')]); header('Location:index.php'); exit;} $rows=fetchAll('SELECT * FROM hostel_rooms ORDER BY room_no'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><div class="col"><input name="room_no" class="form-control" placeholder="Room"></div><div class="col"><input name="capacity" type="number" class="form-control" value="3"></div><div class="col"><input name="occupied" type="number" class="form-control" value="0"></div><div class="col"><input name="hostel_fee" type="number" class="form-control" value="0"></div><div class="col"><button class="btn btn-primary">Add</button></div></form><hr><table class="table"><?php foreach($rows as $r):?><tr><td><?=e($r['room_no'])?></td><td><?=$r['occupied']?> / <?=$r['capacity']?></td><td><?=($r['capacity']-$r['occupied'])>0?'Vacant':'Full'?></td><td><?=$r['hostel_fee']?></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
